pub struct Buffer { pub lines: Vec<String>, pub path: Option<String>, } impl Buffer { pub fn new() -> Self { Self { lines: vec![String::new()], path: None } } pub fn insert_line(&mut self, row: usize, col: usize, text: &str) { if row < self.lines.len() { self.lines[row].insert_str(col, text); } } pub fn delete_range(&mut self, row: usize, start: usize, end: usize) { if row < self.lines.len() { let len = self.lines[row].len(); if start < len { let end = end.min(len); self.lines[row].replace_range(start..end, ""); } } } pub fn get_text(&self) -> String { self.lines.join("\n") } }
